column2:
# some neptun ids are messed up
for (i in 1:nrow(GNET_pilot_filtered)){
  if (GNET_pilot_filtered$multichar_knowresp[i] == "capsmlcqiycaps"){
    GNET_pilot_filtered$multichar_knowresp[i] := "mlcqiy"
  }
  if (GNET_pilot_filtered$multichar_knowresp[i] == "capsb2capsd8capsb2"){
    GNET_pilot_filtered$multichar_knowresp[i] := "b2d8b2"
  }
}
